parameters.content:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * Preference hierarchy:
 * - UserNotificationPreferences: Top-level container keyed by user ID.
 * - EmailPreferences: Email-specific settings (enabled, frequency, categories).
 * - SmsPreferences: SMS-specific settings (enabled, categories).
 * - WebhookPreferences: Webhook-specific settings (enabled, url, categories).
 * - NotificationCategoryPreference: Per-category opt-in/out for each notification type.
 *
 * Design notes:
 * - Users who have no stored preferences receive all notifications (opt-out model).
 * - Each channel has a master `enabled` switch — if false, no notifications are
 *   sent on that channel regardless of category settings.
 * - Email-specific: Frequency controls how often digest-style emails are batched.
 *   'immediate' means every notification is sent as it occurs.
 * - SMS-specific: Always immediate delivery (no frequency setting needed).
 * - Webhook-specific: Always immediate delivery; includes a target URL.
 *
 * DECISION CHANGE LOG (2026-03-27):
 * =========================================================================
 * This model was originally designed with an EMAIL-ONLY assumption (Session 3).
 * SMS was added as a notification channel in Session 8 (see src/adapters/sms.adapter.ts),
 * which invalidated the single-channel design.
 *
 * This refactor (Session 9) updates the model to support per-channel preferences
 * for email, SMS, and webhook. Changes:
 *
 * 1. Added `SmsPreferences` interface with enabled + categoryPreferences.
 * 2. Added `WebhookPreferences` interface with enabled + url + categoryPreferences.
 * 3. Added `sms` and `webhook` fields to `UserNotificationPreferences`.
 * 4. Updated `CreatePreferencesInput` and `UpdatePreferencesInput` with optional
 *    `sms` and `webhook` fields.
 * 5. Added `getDefaultSmsPreferences()` and `getDefaultWebhookPreferences()`.
 *
 * Backward compatibility: The `email` field remains unchanged. Existing code
 * that only uses email preferences continues to work without modification.
 * The `sms` and `webhook` fields default to all-enabled when not explicitly set.
 * =========================================================================
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': Send each notification as it occurs.
 * - 'daily': Batch notifications into a daily digest.
 * - 'weekly': Batch notifications into a weekly digest.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Per-category notification preference.
 * Maps a notification type to whether the user wants to receive it.
 */
export interface NotificationCategoryPreference {
  /** The notification type this preference applies to. */
  category: NotificationType;
  /** Whether the user wants to receive this category of notification. */
  enabled: boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master switch: if false, no email notifications are sent. */
  enabled: boolean;
  /** How frequently email notifications are delivered. */
  frequency: EmailFrequency;
  /** Per-category preferences. Categories not listed default to enabled. */
  categoryPreferences: NotificationCategoryPreference[];
}

/**
 * SMS-specific notification preferences.
 *
 * SMS is always delivered immediately (no frequency setting).
 */
export interface SmsPreferences {
  /** Master switch: if false, no SMS notifications are sent. */
  enabled: boolean;
  /** Per-category preferences. Categories not listed default to enabled. */
  categoryPreferences: NotificationCategoryPreference[];
}

/**
 * Webhook-specific notification preferences.
 *
 * Webhooks deliver JSON payloads to a configured URL immediately.
 */
export interface WebhookPreferences {
  /** Master switch: if false, no webhook notifications are sent. */
  enabled: boolean;
  /** The target URL for webhook delivery. */
  url: string;
  /** Per-category preferences. Categories not listed default to enabled. */
  categoryPreferences: NotificationCategoryPreference[];
}

/**
 * Complete user notification preferences.
 *
 * Contains per-channel settings for all supported notification channels.
 */
export interface UserNotificationPreferences {
  /** Unique preferences ID (e.g., pref-0001). */
  id: string;
  /** The user ID these preferences belong to. */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings. */
  sms: SmsPreferences;
  /** Webhook notification settings. */
  webhook: WebhookPreferences;
  /** When the preferences were created. */
  createdAt: Date;
  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for creating user notification preferences.
 * All channel fields are optional — defaults are applied by the service.
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating existing user notification preferences.
 * Only the fields provided will be changed.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Default email preferences for new users.
 * Opt-out model: all notifications enabled by default.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categoryPreferences: [
      { category: 'order_confirmation', enabled: true },
      { category: 'order_status_update', enabled: true },
      { category: 'welcome', enabled: true },
      { category: 'account_updated', enabled: true },
    ],
  };
}

/**
 * Default SMS preferences for new users.
 * Opt-out model: all notifications enabled by default.
 * SMS does not have a frequency setting — always immediate.
 */
export function getDefaultSmsPreferences(): SmsPreferences {
  return {
    enabled: true,
    categoryPreferences: [
      { category: 'order_confirmation', enabled: true },
      { category: 'order_status_update', enabled: true },
      { category: 'welcome', enabled: true },
      { category: 'account_updated', enabled: true },
    ],
  };
}

/**
 * Default webhook preferences for new users.
 * Opt-out model: webhook is disabled by default (requires URL configuration).
 */
export function getDefaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: false,
    url: '',
    categoryPreferences: [
      { category: 'order_confirmation', enabled: true },
      { category: 'order_status_update', enabled: true },
      { category: 'welcome', enabled: true },
      { category: 'account_updated', enabled: true },
    ],
  };
}

/**
 * Repository for UserNotificationPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 *
 * The preferences collection stores one record per user. Each record
 * contains the full notification preferences including email, SMS, and
 * webhook settings with per-category opt-in/out preferences.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserNotificationPreferences,
  NotificationCategoryPreference,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserNotificationPreferences['email']['frequency'],
        categoryPreferences: JSON.parse(
          record['emailCategoryPreferences'] as string,
        ) as NotificationCategoryPreference[],
      },
      sms: {
        enabled: (record['smsEnabled'] as boolean) ?? true,
        categoryPreferences: record['smsCategoryPreferences']
          ? (JSON.parse(record['smsCategoryPreferences'] as string) as NotificationCategoryPreference[])
          : [
              { category: 'order_confirmation', enabled: true },
              { category: 'order_status_update', enabled: true },
              { category: 'welcome', enabled: true },
              { category: 'account_updated', enabled: true },
            ],
      },
      webhook: {
        enabled: (record['webhookEnabled'] as boolean) ?? false,
        url: (record['webhookUrl'] as string) ?? '',
        categoryPreferences: record['webhookCategoryPreferences']
          ? (JSON.parse(record['webhookCategoryPreferences'] as string) as NotificationCategoryPreference[])
          : [
              { category: 'order_confirmation', enabled: true },
              { category: 'order_status_update', enabled: true },
              { category: 'welcome', enabled: true },
              { category: 'account_updated', enabled: true },
            ],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategoryPreferences: JSON.stringify(entity.email.categoryPreferences),
      smsEnabled: entity.sms.enabled,
      smsCategoryPreferences: JSON.stringify(entity.sms.categoryPreferences),
      webhookEnabled: entity.webhook.enabled,
      webhookUrl: entity.webhook.url,
      webhookCategoryPreferences: JSON.stringify(entity.webhook.categoryPreferences),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find notification preferences for a specific user.
   *
   * @param userId - The user ID to look up preferences for.
   * @returns The user's preferences, or undefined if none are stored.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations on notification preferences and provides a
 * query interface for the NotificationService to check whether a given
 * notification should be delivered to a user on any supported channel.
 *
 * Design decisions:
 * - Opt-out model: users without stored preferences receive all notifications.
 * - Each channel has a master `enabled` switch; if false, all notifications
 *   on that channel are suppressed regardless of category settings.
 * - Categories not explicitly listed in `categoryPreferences` default to enabled.
 * - This service does NOT emit events — it is a passive data service queried
 *   by the NotificationService during dispatch.
 *
 * Supported channels:
 * - email: Supports enabled, frequency, and per-category preferences.
 * - sms: Supports enabled and per-category preferences (always immediate).
 * - webhook: Supports enabled, url, and per-category preferences.
 *
 * DECISION CHANGE (2026-03-27, Session 9):
 * Originally built with an email-only assumption (Session 3). Now updated
 * to support per-channel preferences for email, SMS, and webhook after
 * SMS was added in Session 8. See user-preferences.ts for full change log.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserNotificationPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  getDefaultEmailPreferences,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Used in tests. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  // ---------------------------------------------------------------------------
  // CRUD Operations
  // ---------------------------------------------------------------------------

  /**
   * Create notification preferences for a user.
   *
   * If the user already has preferences, throws an error. Use
   * `updatePreferences` to modify existing preferences.
   *
   * @param input - The preferences to create. Defaults are applied for omitted fields.
   * @returns The created preferences.
   */
  createPreferences(input: CreatePreferencesInput): UserNotificationPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    const existing = this.preferencesRepository.findByUserId(input.userId);
    validatePreferencesNotExist(input.userId, existing);

    const emailDefaults = getDefaultEmailPreferences();
    const emailPrefs: EmailPreferences = {
      enabled: input.email?.enabled ?? emailDefaults.enabled,
      frequency: input.email?.frequency ?? emailDefaults.frequency,
      categoryPreferences:
        input.email?.categoryPreferences ?? emailDefaults.categoryPreferences,
    };

    const smsDefaults = getDefaultSmsPreferences();
    const smsPrefs: SmsPreferences = {
      enabled: input.sms?.enabled ?? smsDefaults.enabled,
      categoryPreferences:
        input.sms?.categoryPreferences ?? smsDefaults.categoryPreferences,
    };

    const webhookDefaults = getDefaultWebhookPreferences();
    const webhookPrefs: WebhookPreferences = {
      enabled: input.webhook?.enabled ?? webhookDefaults.enabled,
      url: input.webhook?.url ?? webhookDefaults.url,
      categoryPreferences:
        input.webhook?.categoryPreferences ?? webhookDefaults.categoryPreferences,
    };

    const now = new Date();
    const preferences: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: emailPrefs,
      sms: smsPrefs,
      webhook: webhookPrefs,
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Preferences created: ${preferences.id} for user ${input.userId}`);

    return preferences;
  }

  /**
   * Get notification preferences for a user.
   *
   * @param userId - The user ID to look up.
   * @returns The user's preferences, or undefined if none are stored.
   */
  getPreferences(userId: string): UserNotificationPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Update notification preferences for a user.
   *
   * Only the provided fields are changed; all others remain as-is.
   *
   * @param userId - The user whose preferences to update.
   * @param input - The fields to update.
   * @returns The updated preferences.
   * @throws Error if no preferences exist for the user.
   */
  updatePreferences(
    userId: string,
    input: UpdatePreferencesInput,
  ): UserNotificationPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    validatePreferencesExist(userId, existing);

    const updatedEmail: EmailPreferences = {
      enabled: input.email?.enabled ?? existing.email.enabled,
      frequency: input.email?.frequency ?? existing.email.frequency,
      categoryPreferences:
        input.email?.categoryPreferences ?? existing.email.categoryPreferences,
    };

    const updatedSms: SmsPreferences = {
      enabled: input.sms?.enabled ?? existing.sms.enabled,
      categoryPreferences:
        input.sms?.categoryPreferences ?? existing.sms.categoryPreferences,
    };

    const updatedWebhook: WebhookPreferences = {
      enabled: input.webhook?.enabled ?? existing.webhook.enabled,
      url: input.webhook?.url ?? existing.webhook.url,
      categoryPreferences:
        input.webhook?.categoryPreferences ?? existing.webhook.categoryPreferences,
    };

    const updated = this.preferencesRepository.update(existing.id, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Preferences updated: ${existing.id} for user ${userId}`);

    return updated;
  }

  /**
   * Delete notification preferences for a user.
   *
   * After deletion, the user will receive all notifications (default behaviour).
   *
   * @param userId - The user whose preferences to delete.
   * @returns true if preferences were deleted, false if none existed.
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }

    return this.preferencesRepository.delete(existing.id);
  }

  /**
   * Get or create preferences for a user.
   *
   * If the user has no stored preferences, creates default preferences.
   * This is a convenience method for the notification check flow.
   *
   * @param userId - The user ID.
   * @returns The user's preferences (existing or newly created defaults).
   */
  getOrCreatePreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  // ---------------------------------------------------------------------------
  // Notification Check Interface
  // ---------------------------------------------------------------------------

  /**
   * Check whether a notification should be sent to a user on a given channel.
   *
   * This is the primary query used by the NotificationService before dispatching.
   * It checks:
   * 1. Whether the channel is enabled (master switch).
   * 2. Whether the specific notification category is enabled.
   *
   * Users without stored preferences are assumed to want all notifications
   * (opt-out model).
   *
   * @param userId - The user to check.
   * @param channel - The notification channel ('email', 'sms', 'webhook', etc.).
   * @param notificationType - The type of notification being sent.
   * @returns true if the notification should be sent, false if suppressed.
   */
  shouldSendNotification(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No stored preferences — opt-out model means send everything.
    if (!preferences) {
      this.logger.debug(
        `No preferences for user ${userId}; defaulting to send`,
      );
      return true;
    }

    if (channel === 'email') {
      return this.shouldSendEmail(preferences, notificationType);
    }

    if (channel === 'sms') {
      return this.shouldSendSms(preferences, notificationType);
    }

    if (channel === 'webhook') {
      return this.shouldSendWebhook(preferences, notificationType);
    }

    // Unknown or unsupported channels (e.g. 'in_app') default to sending.
    return true;
  }

  /**
   * Check whether a specific email notification should be sent based on
   * user preferences.
   *
   * @param preferences - The user's stored preferences.
   * @param notificationType - The notification type to check.
   * @returns true if the email should be sent.
   */
  private shouldSendEmail(
    preferences: UserNotificationPreferences,
    notificationType: NotificationType,
  ): boolean {
    // Master switch check.
    if (!preferences.email.enabled) {
      this.logger.debug(
        `Email disabled for user ${preferences.userId}; suppressing ${notificationType}`,
      );
      return false;
    }

    // Category-level check.
    const categoryPref = preferences.email.categoryPreferences.find(
      (cp) => cp.category === notificationType,
    );

    // Categories not explicitly listed default to enabled.
    if (!categoryPref) {
      return true;
    }

    if (!categoryPref.enabled) {
      this.logger.debug(
        `Category ${notificationType} disabled for user ${preferences.userId} on email; suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Check whether a specific SMS notification should be sent based on
   * user preferences.
   *
   * @param preferences - The user's stored preferences.
   * @param notificationType - The notification type to check.
   * @returns true if the SMS should be sent.
   */
  private shouldSendSms(
    preferences: UserNotificationPreferences,
    notificationType: NotificationType,
  ): boolean {
    // Master switch check.
    if (!preferences.sms.enabled) {
      this.logger.debug(
        `SMS disabled for user ${preferences.userId}; suppressing ${notificationType}`,
      );
      return false;
    }

    // Category-level check.
    const categoryPref = preferences.sms.categoryPreferences.find(
      (cp) => cp.category === notificationType,
    );

    // Categories not explicitly listed default to enabled.
    if (!categoryPref) {
      return true;
    }

    if (!categoryPref.enabled) {
      this.logger.debug(
        `Category ${notificationType} disabled for user ${preferences.userId} on SMS; suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Check whether a specific webhook notification should be sent based on
   * user preferences.
   *
   * @param preferences - The user's stored preferences.
   * @param notificationType - The notification type to check.
   * @returns true if the webhook should be sent.
   */
  private shouldSendWebhook(
    preferences: UserNotificationPreferences,
    notificationType: NotificationType,
  ): boolean {
    // Master switch check.
    if (!preferences.webhook.enabled) {
      this.logger.debug(
        `Webhook disabled for user ${preferences.userId}; suppressing ${notificationType}`,
      );
      return false;
    }

    // Category-level check.
    const categoryPref = preferences.webhook.categoryPreferences.find(
      (cp) => cp.category === notificationType,
    );

    // Categories not explicitly listed default to enabled.
    if (!categoryPref) {
      return true;
    }

    if (!categoryPref.enabled) {
      this.logger.debug(
        `Category ${notificationType} disabled for user ${preferences.userId} on webhook; suppressing`,
      );
      return false;
    }

    return true;
  }
}

