  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter({ stubMode: true });
      notificationService.registerAdapter(emailAdapter);
      notificationService.setPreferencesService(service);
      resetNotificationIdCounter();
    });

    it('should send notifications when user has no preferences (opt-out)', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');
    });

    it('should suppress notifications when email is disabled', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toContain('Suppressed by user notification preferences');
      expect(notifications[0]?.metadata?.['suppressedByPreferences']).toBe(true);
    });

    it('should suppress notifications for disabled category', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: false },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: true },
          ],
        },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toContain('Suppressed');
    });

    it('should send notifications for enabled categories even when some are disabled', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: false },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: false },
          ],
        },
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.type).toBe('welcome');
    });

    it('should work without preferences service (backwards compatible)', async () => {
      // Create a new notification service without preferences
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);
      freshNotifService.registerAdapter(new EmailAdapter({ stubMode: true }));
      // Note: no setPreferencesService call

