        metadata: { userId: 'user-1' },
      });

      expect(record.status).toBe('failed');
      expect(record.failureReason).toContain('Suppressed by user notification preferences');
    });

    it('should send webhook notifications when webhook is enabled', async () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true, url: 'https://hooks.example.com' },
      });

      const webhookAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com',
        stubMode: true,
      });
      notificationService.registerAdapter(webhookAdapter);

      const record = await notificationService.send({
        type: 'order_confirmation',
        recipient: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'webhook',
        metadata: { userId: 'user-1' },
      });

      expect(record.status).toBe('sent');
    });

    it('should respect per-channel preferences independently across channels', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: false },
        webhook: { enabled: true, url: 'https://hooks.example.com' },
      });

      const smsAdapter = new SmsAdapter({ stubMode: true });
      const webhookAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com',
        stubMode: true,
      });
      notificationService.registerAdapter(smsAdapter);
      notificationService.registerAdapter(webhookAdapter);

      // Email should send
      const emailRecord = await notificationService.send({
        type: 'order_confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'email',
        metadata: { userId: 'user-1' },
      });
      expect(emailRecord.status).toBe('sent');

      // SMS should be suppressed
      const smsRecord = await notificationService.send({
        type: 'order_confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'sms',
        metadata: { userId: 'user-1' },
      });
      expect(smsRecord.status).toBe('failed');
      expect(smsRecord.failureReason).toContain('Suppressed');

      // Webhook should send
      const webhookRecord = await notificationService.send({
        type: 'order_confirmation',
        recipient: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        channel: 'webhook',
        metadata: { userId: 'user-1' },
      });
      expect(webhookRecord.status).toBe('sent');
    });
  });
